=== Dockerfile ===
FROM php:8.1-apache
COPY . /var/www/html/
RUN docker-php-ext-install mysqli
EXPOSE 80

=== requirements.txt ===
# No requirements for PHP

=== .htaccess ===
<IfModule mod_rewrite.c>
RewriteEngine On
RewriteRule ^index\.php$ - [L]
RewriteCond %{REQUEST_FILENAME} !-f
RewriteCond %{REQUEST_FILENAME} !-d
RewriteRule . /index.php [L]
</IfModule>

=== index.php ===
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>File Upload App</title>
</head>
<body>
    <h1>Welcome to the File Upload App</h1>
    <a href="register.php">Register</a> | <a href="login.php">Login</a> | <a href="upload.php">Upload File</a> | <a href="search.php">Search</a>
